    else{
        ll p = (1LL<<k);

        ll ans = 0;
        if(p <= n){
            ans += n-p+1;
            ll it = k-1;
            for(ll i=it; i>=0; i--){
                ll x = k-i;
                ll ct = 0;
                for(ll j=x; j<=i; j++){
